// Time:  O(logn)
// Space: O(1)

class Solution {
public:
    string encode(int num) {
        string result;
        while (num) {
            result.push_back((num % 2) ? '0' : '1');
            num = (num - 1) / 2;
        }
        reverse(result.begin(), result.end());
        return result;
    }
};

# Time:  O(logn)
# Space: O(1)

class Solution(object):
    def encode(self, num):
        """
        :type num: int
        :rtype: str
        """
        result = []
        while num:
            result.append('0' if num%2 else '1')
            num = (num-1)//2
        return "".join(reversed(result))
